/**
 * GOOGLE ANALYTICS (GA4) DATA FETCHER
 *
 * Runs on a schedule (see backend/jobs/scheduler.js).
 * Pulls REAL GA4 data via the GA4 Data API (no mock/random values).
 *
 * Attribution strategy:
 * - UTM links generated by the backend include `utm_term=<utmLinkId>`
 * - GA4 exposes this as dimension `sessionManualTerm`
 * - We query GA4 by `sessionManualTerm` values to map metrics to each UTM link
 *
 * Writes:
 * - Per-link per-day records into Firestore `earnings` (docId: <utmLinkDocId>_<YYYY-MM-DD>)
 * - Per-link aggregate into `campaign_analytics` (docId: <utmLinkDocId>)
 * - Summary doc per member into `earnings/<memberId>` (legacy support)
 * - Summary doc into `admin_stats/latest`
 */

import { google } from 'googleapis';
import { db, admin } from '../config/firebase-admin.js';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// GA4 Configuration
const GA4_PROPERTY_ID = process.env.GA4_PROPERTY_ID || '519091919'; // captionmood.com GA4 Property ID
const LOOKBACK_DAYS = Number(process.env.GA_LOOKBACK_DAYS || 30); // fetch last N days (inclusive)
const COMMISSION_RATE = Number(process.env.MEMBER_COMMISSION_RATE || 0.70); // Members earn 70%
const ADMIN_RATE = Number(process.env.ADMIN_COMMISSION_RATE || (1 - COMMISSION_RATE)); // Admin earns the rest
const GA_KEY_FILE =
  process.env.GOOGLE_ANALYTICS_KEY_FILE ||
  path.join(__dirname, '..', '..', 'config', 'google-analytics-key.json');

// Support serverless/hosted environments where the key file is not present.
// You can provide the service account JSON directly as an environment variable.
const GA_SERVICE_ACCOUNT_JSON =
  process.env.GOOGLE_ANALYTICS_SERVICE_ACCOUNT ||
  process.env.FIREBASE_SERVICE_ACCOUNT;

function chunkArray(arr, size) {
  const chunks = [];
  for (let i = 0; i < arr.length; i += size) {
    chunks.push(arr.slice(i, i + size));
  }
  return chunks;
}

function isoDateFromGaDate(gaDate) {
  // GA4 date comes as YYYYMMDD
  if (!gaDate || typeof gaDate !== 'string' || gaDate.length !== 8) return null;
  const y = gaDate.slice(0, 4);
  const m = gaDate.slice(4, 6);
  const d = gaDate.slice(6, 8);
  return `${y}-${m}-${d}`;
}

function getUtcDateRange(lookbackDays) {
  const end = new Date();
  end.setUTCHours(0, 0, 0, 0);
  const start = new Date(end);
  const days = Number.isFinite(lookbackDays) && lookbackDays > 0 ? lookbackDays : 30;
  start.setUTCDate(start.getUTCDate() - (days - 1));
  const startDate = start.toISOString().slice(0, 10);
  const endDate = end.toISOString().slice(0, 10);
  return { startDate, endDate };
}

function safeNumber(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : 0;
}

function calculateEarnings(revenue) {
  const gross = safeNumber(revenue);
  return {
    memberEarnings: Math.round(gross * COMMISSION_RATE * 100) / 100,
    adminEarnings: Math.round(gross * ADMIN_RATE * 100) / 100
  };
}

function getUtmTermFromUrl(trackingUrl) {
  try {
    if (!trackingUrl) return null;
    const u = new URL(trackingUrl);
    return u.searchParams.get('utm_term');
  } catch {
    return null;
  }
}

function tryPatchUrlWithUtmTerm(inputUrl, { utmTerm, memberId } = {}) {
  try {
    if (!inputUrl) return null;
    const u = new URL(inputUrl);
    if (utmTerm) u.searchParams.set('utm_term', utmTerm);
    if (memberId) u.searchParams.set('utm_member', memberId);
    return u.toString();
  } catch {
    return null;
  }
}

/**
 * Create Google Analytics client
 */
async function createAnalyticsClient() {
  try {
    let auth;

    if (GA_SERVICE_ACCOUNT_JSON) {
      let credentials;
      try {
        credentials = JSON.parse(GA_SERVICE_ACCOUNT_JSON);
      } catch {
        console.warn('⚠️ GOOGLE_ANALYTICS_SERVICE_ACCOUNT / FIREBASE_SERVICE_ACCOUNT is not valid JSON');
        return null;
      }

      auth = new google.auth.GoogleAuth({
        credentials,
        scopes: ['https://www.googleapis.com/auth/analytics.readonly']
      });
    } else {
      if (!fs.existsSync(GA_KEY_FILE)) {
        console.warn('⚠️ GA service account key not found at:', GA_KEY_FILE);
        return null;
      }

      auth = new google.auth.GoogleAuth({
        keyFile: GA_KEY_FILE,
        scopes: ['https://www.googleapis.com/auth/analytics.readonly']
      });
    }

    const authClient = await auth.getClient();
    const analyticsData = google.analyticsdata({
      version: 'v1beta',
      auth: authClient
    });

    return analyticsData;
    
  } catch (error) {
    console.error('❌ Failed to create GA client:', error.message);
    throw error;
  }
}

async function fetchActiveUtmLinks() {
  console.log('📊 Fetching active UTM links from Firestore...');

  // Prefer the new schema: status == 'active'
  let snapshot;
  try {
    snapshot = await db.collection('utm_links').where('status', '==', 'active').get();
  } catch (e) {
    console.warn('⚠️ Failed querying utm_links by status, falling back:', e.message);
  }

  if (!snapshot || snapshot.empty) {
    // Legacy fallback: active == true
    try {
      snapshot = await db.collection('utm_links').where('active', '==', true).get();
    } catch (e) {
      console.warn('⚠️ Failed querying utm_links by legacy active flag:', e.message);
    }
  }

  if (!snapshot || snapshot.empty) {
    console.log('⚠️ No active UTM links found');
    return [];
  }

  const links = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
  console.log(`📊 Found ${links.length} active UTM links`);
  return links;
}

async function runGaReportByUtmTerms(analyticsData, propertyId, utmTerms, startDate, endDate) {
  const property = `properties/${propertyId}`;

  const response = await analyticsData.properties.runReport({
    property,
    requestBody: {
      dateRanges: [{ startDate, endDate }],
      dimensions: [
        { name: 'date' },
        { name: 'sessionManualTerm' }
      ],
      metrics: [
        { name: 'sessions' },
        { name: 'activeUsers' },
        { name: 'totalRevenue' }
      ],
      dimensionFilter: {
        filter: {
          fieldName: 'sessionManualTerm',
          inListFilter: { values: utmTerms }
        }
      },
      limit: 10000
    }
  });

  return response.data;
}

/**
 * Main GA data fetcher function
 */
export async function fetchGAData() {
  try {
    console.log('🔄 Starting GA data fetcher...');
    console.log(`🔑 GA Property ID: ${GA4_PROPERTY_ID}`);

    const analyticsData = await createAnalyticsClient();
    if (!analyticsData) {
      throw new Error('GA client not configured (missing service account key file)');
    }

    const links = await fetchActiveUtmLinks();
    if (links.length === 0) {
      return {
        success: true,
        campaignsProcessed: 0,
        membersUpdated: 0,
        timestamp: new Date().toISOString()
      };
    }

    const nowTs = admin.firestore.Timestamp.now();

    const { startDate, endDate } = getUtcDateRange(LOOKBACK_DAYS);
    console.log(`📅 Date range: ${startDate} → ${endDate} (UTC)`);

    // Map GA utm_term values to Firestore link docs.
    const termToLinkDocId = new Map();
    const linkByDocId = new Map();

    const trackableTerms = [];
    const skippedLinks = [];
    let migratedLinks = 0;

    for (const link of links) {
      linkByDocId.set(link.id, link);

      const trackingUrl = link.trackingUrl || link.url;
      const termFromUrl = getUtmTermFromUrl(trackingUrl);
      let term = link.utmTerm || termFromUrl || null;

      // Auto-migrate legacy links that are missing utm_term
      if (!term) {
        const candidateTerm = link.id;
        const memberId = link.memberId || link.member_id || null;
        const patchedUrl =
          tryPatchUrlWithUtmTerm(trackingUrl, { utmTerm: candidateTerm, memberId }) ||
          tryPatchUrlWithUtmTerm(link.articleUrl, { utmTerm: candidateTerm, memberId });

        try {
          const update = {
            utmTerm: candidateTerm,
            legacyMigratedAt: nowTs
          };
          if (patchedUrl) update.trackingUrl = patchedUrl;

          await db.collection('utm_links').doc(link.id).set(update, { merge: true });

          link.utmTerm = candidateTerm;
          if (patchedUrl) link.trackingUrl = patchedUrl;
          term = candidateTerm;
          migratedLinks += 1;
        } catch (e) {
          // If we can't update the link doc, we still skip it (can't be tracked)
          skippedLinks.push({ id: link.id, reason: `missing utm_term (migration failed: ${e?.message || 'unknown'})` });
          continue;
        }
      }

      if (!term) {
        skippedLinks.push({ id: link.id, reason: 'missing utm_term in trackingUrl' });
        continue;
      }

      termToLinkDocId.set(term, link.id);
      trackableTerms.push(term);
    }

    if (skippedLinks.length > 0) {
      console.warn(`⚠️ Skipping ${skippedLinks.length} UTM links missing utm_term. Recreate those links (or edit them to include utm_term) to enable GA tracking.`);
    }

    if (migratedLinks > 0) {
      console.log(`🛠️ Auto-migrated ${migratedLinks} legacy UTM link(s) to include utm_term=${'<docId>'}.`);
    }

    if (trackableTerms.length === 0) {
      console.log('⚠️ No trackable UTM links found (all missing utm_term)');
      return {
        success: true,
        campaignsProcessed: 0,
        membersUpdated: 0,
        skippedLinks: skippedLinks.length,
        timestamp: new Date().toISOString()
      };
    }

    console.log(`📈 Querying GA for ${trackableTerms.length} utm_term values...`);

    const earningsWrites = [];
    const campaignAgg = new Map(); // linkDocId -> totals
    const memberAgg = new Map(); // memberId -> totals

    const termChunks = chunkArray(trackableTerms, 100);
    let gaRows = 0;

    for (const chunk of termChunks) {
      const data = await runGaReportByUtmTerms(analyticsData, GA4_PROPERTY_ID, chunk, startDate, endDate);
      const rows = data.rows || [];
      gaRows += rows.length;

      for (const row of rows) {
        const gaDate = row.dimensionValues?.[0]?.value;
        const gaTerm = row.dimensionValues?.[1]?.value;
        const date = isoDateFromGaDate(gaDate);
        if (!date || !gaTerm) continue;

        const linkDocId = termToLinkDocId.get(gaTerm);
        if (!linkDocId) continue;

        const link = linkByDocId.get(linkDocId);
        const memberId = link?.memberId || link?.member_id || null;
        if (!memberId) {
          skippedLinks.push({ id: linkDocId, reason: 'missing memberId on utm_links doc' });
          continue;
        }

        const sessions = safeNumber(row.metricValues?.[0]?.value);
        const activeUsers = safeNumber(row.metricValues?.[1]?.value);
        const revenue = safeNumber(row.metricValues?.[2]?.value);

        const { memberEarnings, adminEarnings } = calculateEarnings(revenue);
        const denom = activeUsers > 0 ? activeUsers : (sessions > 0 ? sessions : 0);
        const rpm = denom > 0 ? Math.round((revenue / denom * 1000) * 100) / 100 : 0;
        const memberRpm = denom > 0 ? Math.round((memberEarnings / denom * 1000) * 100) / 100 : 0;

        const earningDocId = `${linkDocId}_${date}`;
        const earningRef = db.collection('earnings').doc(earningDocId);

        earningsWrites.push({
          ref: earningRef,
          data: {
            memberId,
            linkId: linkDocId,
            utmTerm: gaTerm,
            date,
            campaign: link.campaignSlug || link.campaignName || link.campaign_name || 'Campaign',
            campaignName: link.campaignName || link.campaign_name || null,
            medium: link.medium || null,
            source: link.source || null,
            articleTitle: link.articleTitle || null,
            articleUrl: link.articleUrl || null,
            clicks: sessions,
            sessions,
            activeUsers,
            revenue: Math.round(revenue * 100) / 100,
            memberEarnings,
            adminEarnings,
            rpm,
            memberRpm,
            lastUpdated: nowTs
          }
        });

        // Aggregate per-link
        const linkTotals = campaignAgg.get(linkDocId) || { clicks: 0, activeUsers: 0, revenue: 0 };
        linkTotals.clicks += sessions;
        linkTotals.activeUsers += activeUsers;
        linkTotals.revenue += revenue;
        campaignAgg.set(linkDocId, linkTotals);

        // Aggregate per-member
        const memberTotals = memberAgg.get(memberId) || { clicks: 0, activeUsers: 0, revenue: 0, memberEarnings: 0, adminEarnings: 0 };
        memberTotals.clicks += sessions;
        memberTotals.activeUsers += activeUsers;
        memberTotals.revenue += revenue;
        memberTotals.memberEarnings += memberEarnings;
        memberTotals.adminEarnings += adminEarnings;
        memberAgg.set(memberId, memberTotals);
      }
    }

    console.log(`✅ GA rows fetched: ${gaRows}`);
    console.log(`🧾 Earnings records to upsert: ${earningsWrites.length}`);

    // Firestore batch writes (limit 500 operations per batch)
    let batch = db.batch();
    let ops = 0;

    const flush = async () => {
      if (ops === 0) return;
      await batch.commit();
      batch = db.batch();
      ops = 0;
    };

    for (const w of earningsWrites) {
      batch.set(w.ref, w.data, { merge: true });
      ops++;
      if (ops >= 450) {
        await flush();
      }
    }
    await flush();

    // Update campaign_analytics + utm_links totals (best-effort)
    batch = db.batch();
    ops = 0;

    for (const [linkDocId, totals] of campaignAgg.entries()) {
      const link = linkByDocId.get(linkDocId);
      const memberId = link?.memberId || link?.member_id || null;
      const revenue = totals.revenue;
      const { memberEarnings, adminEarnings } = calculateEarnings(revenue);
      const denom = totals.activeUsers > 0 ? totals.activeUsers : (totals.clicks > 0 ? totals.clicks : 0);
      const rpm = denom > 0 ? Math.round((revenue / denom * 1000) * 100) / 100 : 0;

      const analyticsRef = db.collection('campaign_analytics').doc(linkDocId);
      batch.set(analyticsRef, {
        linkId: linkDocId,
        memberId,
        campaignName: link?.campaignName || link?.campaign_name || link?.campaignSlug || 'Campaign',
        campaignSlug: link?.campaignSlug || null,
        medium: link?.medium || null,
        source: link?.source || null,
        clicks: Math.round(totals.clicks),
        users: Math.round(totals.activeUsers),
        revenue: Math.round(revenue * 100) / 100,
        rpm,
        memberEarnings,
        adminEarnings,
        rangeStart: startDate,
        rangeEnd: endDate,
        lastUpdated: nowTs
      }, { merge: true });
      ops++;

      const linkRef = db.collection('utm_links').doc(linkDocId);
      batch.set(linkRef, {
        clicks: Math.round(totals.clicks),
        revenue: Math.round(revenue * 100) / 100,
        activeUsers: Math.round(totals.activeUsers),
        lastSyncedAt: nowTs,
        gaRangeStart: startDate,
        gaRangeEnd: endDate
      }, { merge: true });
      ops++;

      if (ops >= 400) {
        await batch.commit();
        batch = db.batch();
        ops = 0;
      }
    }

    if (ops > 0) {
      await batch.commit();
    }

    // Update per-member legacy summary docs (best-effort)
    batch = db.batch();
    ops = 0;
    for (const [memberId, totals] of memberAgg.entries()) {
      const denom = totals.activeUsers > 0 ? totals.activeUsers : (totals.clicks > 0 ? totals.clicks : 0);
      const avgRpm = denom > 0 ? Math.round((totals.revenue / denom * 1000) * 100) / 100 : 0;

      const summaryRef = db.collection('earnings').doc(memberId);
      batch.set(summaryRef, {
        memberId,
        totalRevenue: Math.round(totals.revenue * 100) / 100,
        totalEarnings: Math.round(totals.memberEarnings * 100) / 100,
        totalClicks: Math.round(totals.clicks),
        averageRPM: avgRpm,
        lastUpdated: nowTs,
        lastUpdateDate: endDate
      }, { merge: true });
      ops++;

      if (ops >= 450) {
        await batch.commit();
        batch = db.batch();
        ops = 0;
      }
    }
    if (ops > 0) {
      await batch.commit();
    }

    // Update admin summary
    let totalRevenue = 0;
    let totalClicks = 0;
    let totalAdminEarnings = 0;
    let totalMemberEarnings = 0;

    for (const totals of memberAgg.values()) {
      totalRevenue += totals.revenue;
      totalClicks += totals.clicks;
      totalAdminEarnings += totals.adminEarnings;
      totalMemberEarnings += totals.memberEarnings;
    }

    await db.collection('admin_stats').doc('latest').set({
      totalRevenue: Math.round(totalRevenue * 100) / 100,
      totalClicks: Math.round(totalClicks),
      totalCampaigns: campaignAgg.size,
      memberEarnings: Math.round(totalMemberEarnings * 100) / 100,
      adminEarnings: Math.round(totalAdminEarnings * 100) / 100,
      rangeStart: startDate,
      rangeEnd: endDate,
      lastUpdated: nowTs,
      lastUpdateDate: new Date().toISOString()
    }, { merge: true });

    console.log(`\n📊 Summary:`);
    console.log(`  Total Revenue (GA): $${Math.round(totalRevenue * 100) / 100}`);
    console.log(`  Total Clicks (sessions): ${Math.round(totalClicks)}`);
    console.log(`  Admin Earnings: $${Math.round(totalAdminEarnings * 100) / 100}`);
    console.log(`  Member Earnings: $${Math.round(totalMemberEarnings * 100) / 100}`);
    console.log(`  Members Updated: ${memberAgg.size}`);

    return {
      success: true,
      campaignsProcessed: campaignAgg.size,
      membersUpdated: memberAgg.size,
      gaRows,
      earningsRecordsUpserted: earningsWrites.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
      totalClicks: Math.round(totalClicks),
      adminEarnings: Math.round(totalAdminEarnings * 100) / 100,
      memberEarnings: Math.round(totalMemberEarnings * 100) / 100,
      skippedLinks: skippedLinks.length,
      timestamp: new Date().toISOString()
    };
    
  } catch (error) {
    console.error('❌ GA Data Fetcher error:', error.message);
    throw error;
  }
}

export default fetchGAData;
